script:
frappe.ui.form.on('Item', {
    refresh: function(frm) {
        moveCustomSelectMasterToTop(frm);

        // On load and master type change, update field labels safely
        setTimeout(() => updateItemLabels(frm), 200);

        // Disable master type dropdown on edit
        if (!frm.is_new() && frm.fields_dict.custom_select_master) {
            frm.set_df_property('custom_select_master', 'read_only', 1);
            frm.fields_dict.custom_select_master.$input.prop('disabled', true);
        } else if (frm.fields_dict.custom_select_master) {
            frm.set_df_property('custom_select_master', 'read_only', 0);
            frm.fields_dict.custom_select_master.$input.prop('disabled', false);
        }

        // Only update labels on change for the dropdown
        if(frm.fields_dict.custom_select_master) {
            frm.fields_dict.custom_select_master.$input.off('change.itemlabel');
            frm.fields_dict.custom_select_master.$input.on('change.itemlabel', function() {
                updateItemLabels(frm);
            });
        }
    },
    custom_select_master: function(frm) {
        updateItemLabels(frm);
    }
});

function moveCustomSelectMasterToTop(frm) {
    let $custom = frm.fields_dict.custom_select_master && $(frm.fields_dict.custom_select_master.wrapper);
    let $heading = $('.form-dashboard');
    if ($custom && $custom.length && $heading.length) {
        if (!$custom.parent().hasClass('item-master-heading-row')) {
            if (!$('#item-master-heading-row').length) {
                $('<div id="item-master-heading-row" class="item-master-heading-row" style="margin-bottom:16px;"></div>').insertAfter($heading);
            }
            $custom.detach().appendTo('#item-master-heading-row');
        }
    }
}

function updateItemLabels(frm) {
    let masterType = (frm.doc.custom_select_master || frm.fields_dict.custom_select_master?.$input.val() || "Item").trim();
    let masterLabel = masterType || "Item";
    const wordBoundaryRegex = /\bItem\b/gi;

    frm.fields.forEach(field => {
        // Only update labels for visible fields, not the dropdown itself
        if (field.df.fieldname && field.df.fieldname !== 'custom_select_master') {
            let $label = $(field.wrapper).find('label');
            if ($label.length) {
                // Store original label text
                let origText = $label.attr('data-orig-label');
                if (!origText) {
                    origText = $label.text();
                    $label.attr('data-orig-label', origText);
                }
                // Always reset to original before replacing
                let labelToSet = origText;
                if (masterLabel && masterLabel !== "Item") {
                    labelToSet = origText.replace(wordBoundaryRegex, masterLabel);
                }
                $label.text(labelToSet);
            }
        }
        // Child table headers
        if (field.df.fieldtype === 'Table' && field.grid && field.grid.wrapper) {
            field.grid.wrapper.find('th').each(function() {
                let $th = $(this);
                let origTh = $th.attr('data-orig-th');
                if (!origTh) {
                    origTh = $th.text();
                    $th.attr('data-orig-th', origTh);
                }
                let thToSet = origTh;
                if (masterLabel && masterLabel !== "Item") {
                    thToSet = origTh.replace(wordBoundaryRegex, masterLabel);
                }
                $th.text(thToSet);
            });
        }
    });

    // Section headings (Section Breaks)
    $('.form-section .section-head').each(function() {
        let $sec = $(this);
        let orig = $sec.attr('data-orig-title');
        if (!orig) {
            orig = $sec.text();
            $sec.attr('data-orig-title', orig);
        }
        let secToSet = orig;
        if (masterLabel && masterLabel !== "Item") {
            secToSet = orig.replace(wordBoundaryRegex, masterLabel);
        }
        $sec.text(secToSet);
    });

    // Main form title
    $('.title-text').each(function() {
        let $title = $(this);
        let orig = $title.attr('data-orig-title');
        if (!orig) {
            orig = $title.text();
            $title.attr('data-orig-title', orig);
        }
        let titleToSet = orig;
        if (masterLabel && masterLabel !== "Item") {
            titleToSet = orig.replace(wordBoundaryRegex, masterLabel);
        }
        $title.text(titleToSet);
    });
}
